import CommonCrypto

struct RSAKey {
    var n: BigInteger
    var e: BigInteger
    var d: BigInteger
    var p: BigInteger
    var q: BigInteger
}

func generateRSAKey() -> RSAKey {
    let keySize = 2048
    let rsaAlgorithm: CCCryptorStatus = cf_rsa_generate_key(kCFStreamEncodingMacIntel, keySize, nil, &p, &q)
    guard rsaAlgorithm == .Success else { fatalError("RSA key generation failed.") }

    let phiN = (p.bitLength - 1) * (q.bitLength - 1)
    let dmp1 = BigInteger(bigInteger: p, exponent: (phiN + 1) / 2)
    let dmq1 = BigInteger(bigInteger: q, exponent: (phiN + 1) / 2)
    let inverseQpModP = BigInteger.modInverse(dmq1, modulus: p)

    let qInvModP = BigInteger.modPow(inverseQpModP, power: phiN, modulo: p * q)

    let d = BigInteger(dmp1) * qInvModP
    return RSAKey(n: p * q, e: 65537, d: d, p: p, q: q)
}